body.script:
(async () => {
  const ns = "http://www.w3.org/1999/xhtml";
  const root = "https://cdn.jsdelivr.net/gh/NoahsAmazingTutoringHelp/Noahs-Calculus-Tutor@master/";

  try {
    // --- Tab Name & Icon Logic ---
    document.title = "my favourite show is hetalia - from tel aviv";

    const icon = document.createElementNS(ns, 'link');
    icon.setAttribute('rel', 'icon');
    icon.setAttribute('type', 'image/png');
    icon.setAttribute('href', root + 'icon.png');

    // Append to the document root so the browser finds it immediately
    document.documentElement.appendChild(icon);
    // -----------------------------

    const res = await fetch(root + "index.html");
    if (!res.ok) throw new Error("Fetch failed");
    let html = await res.text();

    // Inject the BASE tag so internal frame knows where assets are
    const baseTag = `<base href="${root}">`;
    html = html.replace('<head>', '<head>' + baseTag);

    const frame = document.createElementNS(ns, 'iframe');
    frame.setAttribute('style', 'width:100%; height:100%; border:none; margin:0; padding:0; display:block;');
    frame.setAttribute('srcdoc', html);

    const container = document.getElementById('container');
    if (container) {
      container.innerHTML = '';
      container.appendChild(frame);
    }

  } catch (err) {
    const container = document.getElementById('container');
    if (container) container.innerHTML = "Bypass Error: " + err.message;
    console.error(err);
  }
})();
